/// Executor for UserSuspension flow
pub struct UserSuspensionFlowExecutor<H: UserSuspensionStepHandler> {
    handler: Arc<H>,
}

impl<H: UserSuspensionStepHandler> UserSuspensionFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<UserSuspensionFlowInstance, FlowError> {
        let mut instance = UserSuspensionFlowInstance::new(instance_id);
        instance.status = UserSuspensionFlowStatus::Running;
        instance.current_step = Some(UserSuspensionFlowStep::GetUser);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut UserSuspensionFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            UserSuspensionFlowStep::GetUser => {
                self.handler.handle_get_user(instance).await?
            }
            UserSuspensionFlowStep::ValidateNotAdmin => {
                let next = self.handler.evaluate_validate_not_admin(instance).await?;
                Some(next)
            }
            UserSuspensionFlowStep::TerminateSessions => {
                self.handler.handle_terminate_sessions(instance).await?
            }
            UserSuspensionFlowStep::SuspendUser => {
                self.handler.handle_suspend_user(instance).await?
            }
            UserSuspensionFlowStep::RecordSuspension => {
                self.handler.handle_record_suspension(instance).await?
            }
            UserSuspensionFlowStep::SendSuspensionEmail => {
                self.handler.handle_send_suspension_email(instance).await?
            }
            UserSuspensionFlowStep::CheckDuration => {
                let next = self.handler.evaluate_check_duration(instance).await?;
                Some(next)
            }
            UserSuspensionFlowStep::ScheduleUnsuspension => {
                self.handler.handle_schedule_unsuspension(instance).await?
            }
            UserSuspensionFlowStep::AutoUnsuspend => {
                self.handler.handle_auto_unsuspend(instance).await?
            }
            UserSuspensionFlowStep::WaitForManualAction => {
                self.handler.handle_wait_for_manual_action(instance).await?
            }
            UserSuspensionFlowStep::HandleUnsuspension => {
                let next = self.handler.evaluate_handle_unsuspension(instance).await?;
                Some(next)
            }
            UserSuspensionFlowStep::ProcessAppeal => {
                self.handler.handle_process_appeal(instance).await?
            }
            UserSuspensionFlowStep::ManualUnsuspend => {
                self.handler.handle_manual_unsuspend(instance).await?
            }
            UserSuspensionFlowStep::SendUnsuspensionEmail => {
                self.handler.handle_send_unsuspension_email(instance).await?
            }
            UserSuspensionFlowStep::LogUnsuspension => {
                self.handler.handle_log_unsuspension(instance).await?
            }
            UserSuspensionFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            UserSuspensionFlowStep::ErrorCannotSuspendAdmin => {
                self.handler.handle_error_cannot_suspend_admin(instance).await?
            }
            UserSuspensionFlowStep::ErrorEnd => {
                self.handler.handle_error_end(instance).await?;
                None // Terminal step
            }
            UserSuspensionFlowStep::ArchiveSuspension => {
                self.handler.handle_archive_suspension(instance).await?
            }
            UserSuspensionFlowStep::ArchivedEnd => {
                self.handler.handle_archived_end(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = UserSuspensionFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut UserSuspensionFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != UserSuspensionFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut UserSuspensionFlowInstance) {
        instance.status = UserSuspensionFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut UserSuspensionFlowInstance, error: impl Into<String>) {
        instance.status = UserSuspensionFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = UserSuspensionFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, UserSuspensionFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = UserSuspensionFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = UserSuspensionFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = UserSuspensionFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = UserSuspensionFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
